code.imports:
import { tags } from 'decantr/tags';
import { css } from 'decantr/css';
import { Badge, Button, icon } from 'decantr/components';

code.example:
function DeployLogLive({ entries, status }) {
  const { div, span } = tags;
  const statusVariant = status === 'success' ? 'success' : status === 'failed' ? 'error' : 'warning';
  const levelColor = l => l === 'error' ? '_fgerror' : l === 'warn' ? '_fgwarning' : '_fgmuted';

  return div({ class: css('_flex _col') },
    div({ class: css('_flex _aic _jcsb _px4 _py3 _borderB') },
      div({ class: css('_flex _aic _gap2') },
        icon('terminal', { size: '1em' }),
        span({ class: css('_textsm _bold') }, 'Deploy Log')
      ),
      Badge({ variant: statusVariant }, status)
    ),
    div({ class: css('_p4 _fontmono _textsm _bg[#09090B] _fg[#E4E4E7] _overflow[auto] _mxh[400px]') },
      ...entries.map(e =>
        div({ class: css('_flex _gap2 _py0-5') },
          span({ class: css('_fgmuted _textxs _shrink0') }, e.time),
          span({ class: css(levelColor(e.level)) }, e.message)
        )
      )
    ),
    div({ class: css('_flex _aic _jcsb _px4 _py2 _borderT') },
      span({ class: css('_textxs _fgmuted') }, `${entries.length} lines`),
      div({ class: css('_flex _gap2') },
        Button({ variant: 'ghost', size: 'sm' }, 'Clear'),
        Button({ variant: 'ghost', size: 'sm' }, icon('download', { size: '1em' }), ' Download')
      )
    )
  );
}

code.imports:
import { tags } from 'decantr/tags';
import { createSignal } from 'decantr/state';
import { css } from 'decantr/css';
import { Badge, Button, Chip, Input, icon } from 'decantr/components';

code.example:
function DeployLogHistory({ entries }) {
  const { div, span } = tags;
  const [filter, setFilter] = createSignal('all');
  const levelColor = l => l === 'error' ? '_fgerror' : l === 'warn' ? '_fgwarning' : '_fgmuted';
  const filtered = () => filter() === 'all' ? entries : entries.filter(e => e.level === filter());

  return div({ class: css('_flex _col') },
    div({ class: css('_flex _aic _gap3 _px4 _py3 _borderB') },
      Input({ placeholder: 'Search logs...', size: 'sm', class: css('_flex1') }),
      div({ class: css('_flex _gap1') },
        ...['all', 'info', 'warn', 'error'].map(f =>
          Chip({ label: f, size: 'sm', variant: filter() === f ? 'primary' : 'default', onclick: () => setFilter(f) })
        )
      )
    ),
    div({ class: css('_p4 _fontmono _textsm _bg[#09090B] _fg[#E4E4E7] _overflow[auto] _mxh[500px]') },
      ...filtered().map(e =>
        div({ class: css('_flex _gap2 _py0-5') },
          span({ class: css('_fgmuted _textxs _shrink0') }, e.time),
          Badge({ variant: e.level === 'error' ? 'error' : e.level === 'warn' ? 'warning' : 'default', size: 'xs' }, e.level),
          span({ class: css(levelColor(e.level)) }, e.message)
        )
      )
    ),
    div({ class: css('_flex _aic _jcsb _px4 _py2 _borderT') },
      span({ class: css('_textxs _fgmuted') }, `${filtered().length} entries`),
      Button({ variant: 'ghost', size: 'sm' }, 'Export')
    )
  );
}

